// Pipeline Performance Calculator
INPUT: n (instructions), k (pipeline stages), 
 ideal_CPI = 1, stall_cycles_per_instruction

// Calculate total cycles
total_cycles = k + (n - 1) + (stall_cycles_per_instruction * n)

// Calculate effective CPI
effective_CPI = total_cycles / n
 = ideal_CPI + stall_cycles_per_instruction

// Calculate ideal speedup (no hazards)
ideal_speedup = (n * k) / (k + n - 1)

// Calculate actual speedup vs non-pipelined
non_pipelined_cycles = n * k
actual_speedup = non_pipelined_cycles / total_cycles

// Example: 5-stage pipeline, 1000 instructions, 0.2 stalls/instruction
effective_CPI = 1 + 0.2 = 1.2
total_cycles = 5 + 999 + 200 = 1204
actual_speedup = (1000*5) / 1204 ≈ 4.15×

// Branch penalty calculation
branch_frequency = 0.20
misprediction_rate = 0.40 
flush_penalty = 3 // cycles lost
branch_penalty = branch_frequency * misprediction_rate * flush_penalty
branch_penalty = 0.20 * 0.40 * 3 = 0.24 cycles/instruction
